local function isNumber(s) local seenDigit, seenDot, seenExp, digitAfterExp = false, false, false, true; for i = 1, #s do local ch = s:sub(i, i); if ch >= '0' and ch <= '9' then seenDigit = true; if seenExp then digitAfterExp = true end elseif ch == '+' or ch == '-' then if i ~= 1 and s:sub(i-1,i-1) ~= 'e' and s:sub(i-1,i-1) ~= 'E' then return false end elseif ch == '.' then if seenDot or seenExp then return false end; seenDot = true elseif ch == 'e' or ch == 'E' then if seenExp or not seenDigit then return false end; seenExp = true; digitAfterExp = false else return false end end; return seenDigit and digitAfterExp end
local lines = {}; for line in io.lines() do table.insert(lines, (line:gsub("\r", ""))) end; if #lines > 0 then local t = tonumber(lines[1]); local out = {}; for i = 1, t do out[i] = isNumber(lines[i+1]) and 'true' or 'false' end; io.write(table.concat(out, '\n')) end
